mapper.select:
select empID as id ,concat(workNo,'-',name) as text,jobName as info from view_ehr_employee where empStatus = 1
and empID = #{id}
and ( workNo like concat('%',#{text},'%') or name like concat('%',#{text},'%') or depAllName like concat('%',#{text},'%') or jobName like concat('%',#{text},'%') )
